select public.seed_structured_concept('expansion-batch-03','opioid-constipation','Fundamentals','opioid-related constipation prevention','a client beginning scheduled opioid therapy','Start prescribed bowel prevention with fluids, mobility, fiber when appropriate, and stimulant therapy','Do not wait several days for severe constipation before using the prescribed bowel plan','Abdominal distention with vomiting and absent bowel sounds','Use an antidiarrheal every day','Restrict fluids without a medical reason','Stop all movement to conserve energy','Basic Care and Comfort');
select public.seed_structured_concept('expansion-batch-03','nonpharm-pain','Fundamentals','multimodal pain management','a stable client with postoperative pain despite scheduled medication','Reassess pain and combine prescribed analgesia with positioning, splinting, relaxation, or cold as appropriate','Use pain medicine before activity and combine it with safe non-drug methods','Sudden severe pain out of proportion with a tense swollen limb','Tell the client pain is unavoidable','Withhold analgesia until pain reaches maximum intensity','Apply heat over an acutely bleeding site','Basic Care and Comfort');
select public.seed_structured_concept('expansion-batch-03','sleep-hygiene','Fundamentals','sleep promotion in the hospital','a stable client unable to sleep because of noise and repeated interruptions','Cluster appropriate care, reduce noise and light, and support the client’s usual bedtime routine','Keep a consistent schedule and limit late caffeine, heavy meals, and screen exposure','New nighttime agitation with hypoxemia and acute confusion','Offer caffeine with evening medicines','Wake the client for nonessential tasks hourly','Use sedatives before assessing reversible causes','Basic Care and Comfort');
select public.seed_structured_concept('expansion-batch-03','immobility-rom','Fundamentals','complication prevention during immobility','a bedbound client with weakness but stable vital signs','Reposition, perform prescribed range of motion, protect skin, and promote pulmonary hygiene','Participate in gradual mobility and ankle exercises as directed and report calf pain or breathlessness','A warm swollen unilateral calf with sudden dyspnea','Place pillows directly behind flexed knees continuously','Massage a painful swollen calf','Maintain one position to conserve strength','Basic Care and Comfort');

-- Psychosocial Integrity (6 / 18)
select public.seed_structured_concept('expansion-batch-03','complicated-grief','Mental Health','possible prolonged grief disorder','persistent disabling yearning and inability to function long after a death','Assess safety, functioning, culture, supports, and need for grief-focused treatment','Grief varies, but persistent inability to function or thoughts of self-harm require professional help','A stated wish to die in order to reunite with the deceased','Tell the client to remove every reminder immediately','Set a fixed deadline for completing grief','Avoid discussing the deceased under all circumstances','Psychosocial Integrity');
