select public.seed_structured_concept('expansion-batch-03','auditory-hallucinations','Mental Health','command auditory hallucinations','a client says voices are ordering harm to another person','Ask what the voices say, assess intent and means, ensure safety, and reduce stimulation','Use coping methods such as talking with staff or listening to music and report harmful commands immediately','The client has obtained a weapon and intends to obey the voice','Agree that the voices are real','Challenge the client aggressively to stop pretending','Leave the client alone with access to hazards','Psychosocial Integrity');
