select public.seed_structured_concept('expansion-batch-04','post-thyroidectomy','Medical-Surgical','post-thyroidectomy complications','a client several hours after thyroid surgery','Keep airway equipment available and assess voice, breathing, neck swelling, and calcium signs','Support the neck and report breathing difficulty, tingling, cramping, or rapidly increasing swelling','Stridor with tense neck swelling','Place the client flat without neck support','Encourage forceful coughing repeatedly','Delay reporting new tingling until morning','Reduction of Risk Potential');
