select public.seed_structured_concept('expansion-batch-04','lumbar-puncture','Medical-Surgical','complications after lumbar puncture','a client after cerebrospinal-fluid sampling','Monitor neurologic status, puncture site, and prescribed positioning and hydration','Report persistent severe headache, fever, drainage, weakness, or confusion','Decreasing consciousness with new focal weakness','Encourage immediate strenuous exercise','Ignore clear drainage from the site','Give anticoagulants without reviewing orders','Reduction of Risk Potential');
