select public.seed_structured_concept('expansion-batch-04','bronchoscopy-recovery','Medical-Surgical','recovery after bronchoscopy','a client with topical airway anesthesia after the procedure','Keep NPO until gag and swallow reflexes return and monitor breathing and bleeding','Do not eat or drink until swallowing sensation returns and report breathing difficulty or substantial blood','Stridor with increasing respiratory distress','Offer water immediately to test comfort','Give solid food while the throat is numb','Treat large-volume hemoptysis as expected','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-04','pacemaker-malfunction','Medical-Surgical','pacemaker malfunction','a paced client with dizziness and pacing spikes not followed by QRS complexes','Assess the client, verify connections, notify the provider, and prepare backup pacing','Check the pulse, keep follow-up appointments, and report dizziness, syncope, or persistent hiccups','Syncope with failure to capture on the monitor','Place a magnet routinely over the device','Ignore dizziness when spikes are visible','Allow strong magnets directly over the generator','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-04','cast-neurovascular','Medical-Surgical','neurovascular compromise under a cast','increasing pain, numbness, pallor, and delayed capillary refill','Perform urgent neurovascular assessment and notify the provider immediately','Elevate as directed and report increasing pain, tightness, numbness, coolness, or color change','Inability to move digits with worsening pain despite medication','Insert objects under the cast to scratch','Cover a damp cast with plastic','Wait for complete pulse loss before reporting','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-04','tracheostomy-obstruction','Medical-Surgical','tracheostomy obstruction','sudden distress, noisy breathing, and inability to pass a suction catheter','Call for help, remove the inner cannula if applicable, suction, and prepare emergency airway equipment','Humidify as directed and report thick secretions, difficult suctioning, or breathing distress','Cyanosis with absent airflow through the tube','Force the suction catheter repeatedly','Leave the obturator unavailable','Cover the tracheostomy opening tightly','Reduction of Risk Potential');

-- Physiological Adaptation
select public.seed_structured_concept('expansion-batch-04','septic-shock','Emergency and Critical Care','septic shock','suspected infection, lactate elevation, hypotension, and altered perfusion','Obtain cultures promptly, begin prescribed broad-spectrum antibiotics and fluids, and reassess perfusion','Seek early care for infection with confusion, breathing difficulty, mottled skin, or very low urine output','Persistent hypotension and rising lactate after initial fluids','Delay antibiotics until every culture is final','Give only hypotonic oral fluids','Ignore falling urine output','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','anaphylactic-shock','Emergency and Critical Care','anaphylaxis','wheezing, urticaria, facial swelling, and hypotension after medication','Give intramuscular epinephrine promptly and support airway and circulation','Carry prescribed epinephrine, use it immediately for systemic symptoms, and call emergency services','Increasing stridor with rapidly falling blood pressure','Give an oral antihistamine as the only first treatment','Make the client walk to improve circulation','Delay epinephrine until a rash spreads','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','neurogenic-shock','Emergency and Critical Care','neurogenic shock after spinal injury','hypotension, bradycardia, warm skin, and impaired temperature regulation','Maintain spinal alignment, support blood pressure, and treat bradycardia as prescribed','Prevent pressure injury and report dizziness, breathing change, or temperature problems','Worsening hypotension with bradycardia and respiratory weakness','Place the client upright without support','Apply direct high heat to numb skin','Assume warm skin excludes shock','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','acute-chest-syndrome','Medical-Surgical','acute chest syndrome','sickle cell disease with fever, chest pain, infiltrate, and hypoxemia','Give oxygen, analgesia, antibiotics and supportive therapy as prescribed and prepare escalation','Seek emergency care for fever, chest pain, cough, or breathing difficulty','Rapidly increasing oxygen requirement with multilobar infiltrates','Restrict fluids completely','Delay antibiotics until sputum culture results','Use cold exposure to reduce pain','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','myasthenic-crisis','Medical-Surgical','myasthenic crisis','rapidly worsening bulbar weakness, weak cough, and respiratory fatigue','Assess respiratory strength, protect the airway, and prepare ventilatory support','Take medicines on schedule and report infection, swallowing difficulty, or increasing weakness','Declining vital capacity with inability to handle secretions','Give food before swallowing assessment','Administer sedatives for distress','Delay respiratory measurements until cyanosis','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','adrenal-crisis','Medical-Surgical','acute adrenal crisis','vomiting, severe hypotension, hyponatremia, hyperkalemia, and hypoglycemia','Give prescribed IV hydrocortisone, isotonic fluid, and glucose support promptly','Never stop steroids abruptly and use prescribed stress dosing during illness','Refractory hypotension with worsening altered consciousness','Restrict sodium and fluid','Withhold steroid until cortisol results return','Encourage strenuous activity','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','malignant-hyperthermia','Emergency and Critical Care','malignant hyperthermia','rapid carbon-dioxide rise, muscle rigidity, tachycardia, and hyperthermia during anesthesia','Stop triggering agents, give dantrolene, cool the client, and treat complications','Tell anesthesia teams about personal or family reactions and consider medical-alert identification','Generalized rigidity with rapidly rising end-tidal carbon dioxide','Continue the anesthetic at a lower dose','Use antipyretics as the only treatment','Delay dantrolene until genetic confirmation','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-04','tumor-lysis','Medical-Surgical','tumor lysis syndrome','recent chemotherapy with hyperkalemia, hyperphosphatemia, hypocalcemia, and rising uric acid','Begin prescribed hydration, cardiac monitoring, and uric-acid and electrolyte management','Maintain prescribed hydration and report weakness, cramping, reduced urine, or palpitations','Peaked T waves with oliguria and rising creatinine','Give potassium supplements','Restrict fluids without an indication','Delay laboratory monitoring for several days','Physiological Adaptation');

