select public.seed_structured_concept('expansion-batch-11','care-conference','Leadership and Delegation','an interdisciplinary care conference','a complex client has conflicting goals across disciplines','Center the client’s goals, clarify responsibilities, resolve conflicts, and document the shared plan','Prepare priorities and questions and identify the person coordinating follow-up','Disciplines implement contradictory plans that create immediate harm','Exclude the client','Use the meeting only to assign blame','Leave decisions undocumented','Management of Care');
select public.seed_structured_concept('expansion-batch-11','critical-result-readback','Leadership and Delegation','communication of a critical laboratory result','the laboratory reports a life-threatening value by telephone','Write and read back the result, identify the client, assess promptly, and notify the responsible clinician','Expect urgent results to be repeated and linked to a clear response plan','A critical value is acknowledged but no client assessment occurs','Record it in the wrong chart','Wait for routine rounds','Ask unlicensed staff to interpret it','Management of Care');
select public.seed_structured_concept('expansion-batch-11','medication-access','Leadership and Delegation','medication access at discharge','a client cannot afford several essential prescriptions','Notify the team before discharge and coordinate formulary alternatives, assistance, and a feasible plan','Explain cost barriers honestly rather than rationing medicines without guidance','The client leaves without insulin or a safe access plan','Tell the client to halve every dose','Assume samples provide permanent access','Delay discussion until medicines run out','Management of Care');
