select public.seed_structured_concept('expansion-batch-11','quality-improvement','Leadership and Delegation','a recurring medication-safety event','several similar near misses occur on one unit','Protect current clients and use nonpunitive system analysis to identify and test process improvements','Report near misses because they reveal hazards before harm occurs','Leadership suppresses reports and the same error reaches a client','Discipline one person without system review','Change many processes without measurement','Hide near misses','Management of Care');
select public.seed_structured_concept('expansion-batch-11','continuity-referral','Leadership and Delegation','a time-sensitive outpatient referral','an abnormal finding requires specialist evaluation after discharge','Confirm the referral, responsible clinician, timeframe, records, and process for tracking completion','Know whom to call if an appointment is not received within the stated timeframe','A suspected malignancy referral is never transmitted or tracked','Hand the client an illegible phone number','Assume another office will follow up','Close the result before completion','Management of Care');

