select public.seed_structured_concept('expansion-batch-11','multidose-vial','Safety and Infection Control','multidose-vial safety','a multidose vial is used in a patient-care area','Dedicate it to one client when it enters the immediate treatment area and access it aseptically','Check storage, dating, contamination, and facility policy before each use','A contaminated vial is reused for several clients','Leave a needle in the stopper','Store beside used syringes','Use beyond the labeled date','Safety and Infection Prevention and Control');
