select public.seed_structured_concept('expansion-batch-11','isolation-transport','Safety and Infection Control','transport under transmission precautions','a client on isolation requires urgent imaging','Coordinate with the destination, contain infectious material, use source control, and clean transport equipment','Leave the room only when necessary and follow masking and hygiene instructions','Uncontained drainage contaminates common hallways','Remove every precaution during transport','Make unnecessary stops','Return equipment without disinfection','Safety and Infection Prevention and Control');

