select public.seed_structured_concept('expansion-batch-11','insomnia-cbt','Mental Health','chronic insomnia','a client spends long periods awake in bed and fears not sleeping','Assess causes and support stimulus control, consistent wake time, and cognitive-behavioral treatment','Use the bed for sleep, leave briefly when unable to sleep, and limit late caffeine and alcohol','Severe sleepiness causes repeated driving near misses','Stay in bed worrying for hours','Use alcohol nightly','Drive while unable to remain awake','Psychosocial Integrity');
