select public.seed_structured_concept('expansion-batch-11','postpartum-psychosis','Maternal and Newborn','postpartum psychosis','days after birth a client is sleepless, disorganized, and hears commands about the infant','Ensure constant safety for parent and infant and obtain emergency psychiatric treatment','Psychosis after birth is an emergency, especially with confusion, mania, or harmful commands','The client states a divine command requires harming the infant','Leave parent and infant alone','Treat as normal adjustment','Delay care until the routine visit','Psychosocial Integrity');
select public.seed_structured_concept('expansion-batch-11','opioid-grief-family','Mental Health','family response to substance-use disorder','family members alternate between rescue, anger, and fear after overdoses','Provide overdose education, naloxone, boundaries, support, and treatment resources','Support recovery without financing unsafe use and seek counseling for family stress','A family member threatens suicide after another overdose','Use blame as motivation','Hide naloxone','Give cash during active unsafe use','Psychosocial Integrity');
select public.seed_structured_concept('expansion-batch-11','terminal-anxiety','Mental Health','anxiety near end of life','a dying client expresses fear, breathlessness, and unfinished concerns','Assess physical causes and goals and provide presence, symptom relief, spiritual or psychosocial support as desired','Discuss fears openly and identify preferred people and comfort practices','Severe uncontrolled distress with new reversible airway compromise','Dismiss fear with false reassurance','Force unwanted spiritual care','Withhold symptom medicine','Psychosocial Integrity');

