select public.seed_structured_concept('expansion-batch-11','oral-hydration','Fundamentals','supporting oral hydration','a stable older adult has low intake and no fluid restriction','Offer preferred accessible fluids regularly and address swallowing, toileting, and assistance barriers','Use frequent small amounts and monitor urine, mouth dryness, dizziness, and weight','New inability to swallow with coughing and hypoxemia','Force thin liquids despite dysphagia','Leave fluids out of reach','Offer only at meals','Basic Care and Comfort');
select public.seed_structured_concept('expansion-batch-11','fever-comfort','Fundamentals','comfort care during fever','a stable client has fever, chills, and diaphoresis','Assess the cause and hydration and use light clothing, fluids, and prescribed antipyretic measures','Avoid overbundling and report confusion, breathing difficulty, rash, or dehydration','Fever with stiff neck, purpura, and hypotension','Use ice-water immersion routinely','Pile on heavy blankets throughout fever','Give aspirin to a child','Basic Care and Comfort');
select public.seed_structured_concept('expansion-batch-11','pruritus-care','Fundamentals','comfort management of pruritus','a client has dry itchy skin without an emergency reaction','Assess cause and use lukewarm bathing, moisturizer, cool environment, and prescribed therapy','Keep nails short and report jaundice, breathing difficulty, infection, or a spreading blistering rash','Itching progresses to facial swelling and wheezing','Use very hot showers','Scratch with sharp objects','Apply unapproved irritants','Basic Care and Comfort');
select public.seed_structured_concept('expansion-batch-11','edema-skin','Fundamentals','skin care with severe edema','fragile stretched skin leaks clear fluid','Elevate as prescribed, protect and moisturize skin, reposition, and manage the cause','Inspect daily and report redness, warmth, wounds, sudden asymmetry, or breathlessness','One leg becomes acutely red, painful, and much larger','Massage the painful calf','Apply tight bands','Leave wet linens against skin','Basic Care and Comfort');
