-- Batch 13: respiratory and critical-care catalog.
select public.seed_structured_concept(
  'expansion-batch-13', slug, 'Respiratory', condition, cue, action, teaching,
  danger,
  'Delay respiratory assessment despite worsening symptoms',
  'Give sedating medication before evaluating ventilation',
  'Encourage strenuous activity during acute respiratory instability',
  client_need
)
from (values
('community-pneumonia','community-acquired pneumonia','fever, productive cough, focal crackles, and new infiltrate','Assess oxygenation and severity, obtain indicated cultures, and give timely prescribed antimicrobial and supportive care','Complete antibiotics and seek care for worsening dyspnea, confusion, chest pain, or dehydration','Increasing oxygen need with hypotension and confusion','Physiological Adaptation'),
('aspiration-pneumonitis','acute aspiration pneumonitis','vomiting followed by cough, hypoxemia, and new coarse sounds','Protect the airway, suction as needed, support oxygenation, and evaluate swallowing and lung injury','Use prescribed positioning and texture precautions and report coughing or wet voice during intake','Rapidly worsening hypoxemia and respiratory fatigue','Physiological Adaptation'),
('pleural-effusion','large pleural effusion','progressive dyspnea, dull percussion, and reduced unilateral sounds','Position for breathing, assess oxygenation, and prepare diagnostic or therapeutic drainage','Report increasing breathlessness, pleuritic pain, fever, or rapid recurrence','Severe hypoxemia with mediastinal shift','Physiological Adaptation'),
('empyema','pleural empyema','fever, pleuritic pain, purulent pleural fluid, and loculations','Administer prescribed antibiotics and support complete pleural drainage','Complete treatment and report fever, drain blockage, or worsening chest pain','Sepsis with blocked drainage and respiratory distress','Physiological Adaptation'),
('simple-pneumothorax','a spontaneous pneumothorax','sudden unilateral pain, dyspnea, and reduced breath sounds without shock','Give oxygen, monitor closely, and prepare aspiration or chest drainage based on size and symptoms','Avoid air travel and diving until medically cleared and report sudden recurrent pain','Progression to hypotension, tracheal shift, or severe hypoxemia','Physiological Adaptation'),
('traumatic-hemothorax','traumatic hemothorax','chest trauma with shock, dull percussion, and bloody chest drainage','Support airway and circulation and prepare large-bore chest drainage and hemorrhage control','Report new dyspnea, faintness, increasing pain, or rapidly filling drainage','Massive immediate blood return with persistent shock','Physiological Adaptation'),
('flail-chest','flail chest','paradoxical chest-wall movement, severe pain, and hypoxemia','Support oxygenation and ventilation and provide effective analgesia while assessing pulmonary contusion','Splint as taught and report increasing breathlessness, confusion, or blue color','Exhaustion with rising carbon dioxide and worsening hypoxemia','Physiological Adaptation'),
('rib-fracture','multiple rib fractures','pain causes shallow breathing and weak cough','Provide multimodal analgesia and support deep breathing, coughing, and mobilization','Use prescribed breathing exercises and report fever, dyspnea, or increasing sputum','New hypoxemia with absent unilateral breath sounds','Reduction of Risk Potential'),
('pulmonary-contusion','pulmonary contusion','blunt chest injury with worsening crackles and hypoxemia over hours','Monitor closely, support oxygenation, and use careful fluid and ventilatory management','Symptoms can worsen after injury; return urgently for increasing breathlessness or confusion','Refractory hypoxemia with respiratory fatigue','Physiological Adaptation'),
('bronchiectasis','bronchiectasis','chronic copious sputum, recurrent infection, and hemoptysis','Promote airway clearance, obtain cultures during exacerbation, and give targeted therapy','Use airway-clearance techniques, hydrate as directed, and report increased blood or breathlessness','Large-volume hemoptysis with airway compromise','Physiological Adaptation'),
('cystic-fibrosis-airway','cystic fibrosis pulmonary disease','thick secretions, chronic infection, and declining lung function','Coordinate airway clearance, inhaled therapies, cultures, nutrition, and infection control','Perform airway clearance in the prescribed sequence and avoid close contact with other people with CF','Rapid decline with hemoptysis and severe hypoxemia','Physiological Adaptation'),
('lung-cancer-airway','central lung tumor obstruction','persistent cough, hemoptysis, weight loss, and localized wheeze','Assess airway and bleeding and expedite diagnostic staging and symptom management','Report coughing blood, new stridor, facial swelling, or worsening breathlessness','Massive hemoptysis or superior vena cava syndrome','Physiological Adaptation'),
('nontuberculous-mycobacteria','nontuberculous mycobacterial lung disease','chronic cough, nodular bronchiectatic imaging, and repeated positive cultures','Confirm diagnostic criteria and use specialist-directed multidrug therapy with toxicity monitoring','Adhere to the full regimen and report vision, hearing, liver, or severe gastrointestinal symptoms','Respiratory decline with major medication toxicity','Reduction of Risk Potential'),
('obstructive-sleep-apnea','obstructive sleep apnea','loud snoring, witnessed apnea, and daytime sleepiness','Assess severity and cardiometabolic risk and support prescribed positive-airway-pressure therapy','Use PAP every sleep period and avoid driving when sleepy and unapproved sedatives','Repeated severe desaturation with dangerous daytime sleep episodes','Health Promotion and Maintenance'),
('obesity-hypoventilation','obesity hypoventilation syndrome','daytime hypercapnia, sleep-disordered breathing, and hypoxemia','Support ventilation, avoid excess oxygen without ventilation assessment, and address weight and sleep therapy','Use prescribed PAP and report morning confusion, severe sleepiness, or breathing deterioration','Progressive carbon-dioxide narcosis with shallow respirations','Physiological Adaptation'),
('pulmonary-hypertension','pulmonary arterial hypertension','exertional dyspnea, syncope, loud pulmonic sound, and right-heart strain','Maintain oxygenation and hemodynamics and administer specialist-directed vasodilator therapy','Avoid pregnancy when contraindicated, keep therapy uninterrupted, and report syncope or edema','Syncope with right-heart failure and hypotension','Physiological Adaptation'),
('interstitial-lung-disease','fibrotic interstitial lung disease','dry cough, exertional desaturation, fine crackles, and restrictive testing','Assess oxygen need, function, exposure causes, and prescribed antifibrotic or immune treatment','Use oxygen as prescribed and report rapid symptom change or medication toxicity','Acute exacerbation with diffuse new infiltrates and severe hypoxemia','Physiological Adaptation'),
('sarcoidosis','pulmonary sarcoidosis','bilateral hilar adenopathy with cough and multisystem symptoms','Assess lung, eye, cardiac, neurologic, calcium, and treatment indications','Keep eye and cardiac evaluation and report syncope, vision change, or severe palpitations','High-grade heart block or ventricular dysrhythmia','Reduction of Risk Potential'),
('silicosis','silica-related lung disease','occupational dust exposure with progressive nodular fibrosis','Remove exposure, assess tuberculosis risk and lung function, and provide prevention and supportive care','Use approved respiratory protection and attend tuberculosis screening','Acute respiratory failure or active tuberculosis symptoms','Safety and Infection Prevention and Control'),
('asbestosis','asbestos-related lung disease','remote occupational exposure with fibrosis or pleural disease','Document exposure and monitor respiratory function and malignancy warning signs','Avoid tobacco and report hemoptysis, chest pain, or unexplained weight loss','New pleural mass with rapidly worsening dyspnea','Health Promotion and Maintenance'),
('tracheostomy-routine','routine tracheostomy care','a stable tracheostomy has thick secretions and skin irritation','Humidify, suction only when indicated, clean using aseptic policy, and protect peristomal skin','Keep emergency supplies available and report bleeding, obstruction, displacement, or infection','The tube dislodges with respiratory distress','Basic Care and Comfort'),
('tracheostomy-decannulation','accidental tracheostomy decannulation','a fresh tracheostomy tube comes out and the client cannot breathe','Call emergency support, maintain the airway with trained technique, and use bedside replacement equipment per maturity and policy','Keep obturator and spare tubes at bedside and secure ties correctly','Rapid cyanosis with inability to ventilate','Physiological Adaptation'),
('ventilator-high-pressure','a high-pressure ventilator alarm','a ventilated client has agitation, coarse sounds, and rising airway pressure','Assess the client first, check biting, kinks, secretions, bronchospasm, and lung complications','Alarm limits protect the client and must never be disabled to silence noise','Sudden unilateral absent sounds with hypotension','Reduction of Risk Potential'),
('ventilator-low-pressure','a low-pressure ventilator alarm','delivered volume falls and the circuit appears loose','Assess the client and rapidly check disconnection, cuff leak, tubing, and accidental extubation','Call staff immediately for loose tubing and never reconnect contaminated parts without guidance','The endotracheal tube is displaced with no effective ventilation','Reduction of Risk Potential'),
('vap-prevention','ventilator-associated pneumonia prevention','an intubated client requires prolonged ventilation','Use head elevation, oral care, secretion management, sedation and mobility review, and readiness-to-extubate assessment','Families should clean hands and avoid manipulating airway equipment','New purulent secretions, fever, infiltrate, and worsening oxygenation','Safety and Infection Prevention and Control'),
('closed-suction','endotracheal suctioning','visible secretions and a sawtooth waveform indicate need','Preoxygenate as indicated, use sterile or closed technique, limit passes, and reassess response','Suction is performed for clinical need rather than on a fixed unnecessary schedule','Bradycardia and severe desaturation during suction','Reduction of Risk Potential'),
('unplanned-extubation','unplanned extubation','a ventilated client removes the endotracheal tube','Call for help, support oxygenation and ventilation, and assess need for immediate reintubation','Use communication, comfort, securement, and least-restrictive prevention strategies','Apnea with inability to maintain the airway','Physiological Adaptation'),
('post-extubation-stridor','post-extubation upper-airway edema','inspiratory stridor and retractions develop after extubation','Give prescribed airway therapy and prepare prompt reintubation if worsening','Report noisy breathing, voice change, or increasing effort immediately','Diminishing stridor with decreasing air movement and fatigue','Physiological Adaptation'),
('rapid-sequence-intubation','rapid-sequence intubation','an unstable client requires emergency airway control','Prepare suction, monitoring, preoxygenation, medicines, backup airway, and post-placement confirmation','Family should understand that continuous sedation and ventilator care may follow','Tube placement is not confirmed while oxygenation falls','Physiological Adaptation'),
('oxygen-toxicity','oxygen toxicity risk','prolonged high inspired oxygen is required','Use the lowest oxygen concentration that achieves the target and optimize PEEP and underlying treatment','Do not change prescribed oxygen flow and report worsening cough or chest discomfort','Worsening diffuse lung injury despite prolonged high oxygen exposure','Reduction of Risk Potential'),
('home-oxygen-fire','home oxygen fire safety','a client uses oxygen near smoking materials','Stop ignition sources, keep equipment separated from flame and heat, and coordinate supplier safety','No smoking or vaping near oxygen and use water-based rather than petroleum nasal products','Smoking ignites clothing while oxygen is flowing','Safety and Infection Prevention and Control'),
('pulse-ox-limitations','limitations of pulse oximetry','a client has poor perfusion and possible carbon-monoxide exposure','Assess the client and use appropriate confirmatory testing rather than relying on one saturation value','Motion, nail products, perfusion, dyshemoglobins, and device factors can affect readings','A normal displayed saturation delays treatment of suspected carbon-monoxide poisoning','Reduction of Risk Potential'),
('capnography-rise','rising end-tidal carbon dioxide','a sedated client develops hypoventilation before oxygen saturation falls','Stimulate and support ventilation, stop contributing sedation, and prepare reversal or airway support','Continuous ventilation monitoring can detect respiratory depression early','The waveform disappears with apnea and unresponsiveness','Reduction of Risk Potential'),
('respiratory-acidosis','acute respiratory acidosis','pH 7.22 with PaCO2 68 mm Hg and reduced consciousness','Support ventilation and treat the cause while monitoring potassium and neurologic status','Report increasing sleepiness, shallow breathing, or medicine over-sedation','Progressive hypercapnic coma','Physiological Adaptation'),
('respiratory-alkalosis','acute respiratory alkalosis','pH 7.55 with low PaCO2 during pain or sepsis','Treat the underlying driver and coach breathing only after dangerous causes are assessed','Seek care when rapid breathing accompanies chest pain, fever, hypoxemia, or neurologic symptoms','Hyperventilation is caused by pulmonary embolism or sepsis with instability','Reduction of Risk Potential'),
('metabolic-acidosis','high-anion-gap metabolic acidosis','low pH and bicarbonate with Kussmaul breathing and elevated ketones or lactate','Restore perfusion or insulin as appropriate and monitor potassium and cause-specific response','Follow sick-day and toxicity-prevention plans and report deep breathing or confusion','Severe acidemia with shock and dysrhythmia','Physiological Adaptation'),
('metabolic-alkalosis','chloride-responsive metabolic alkalosis','vomiting or diuretics cause high bicarbonate, low chloride, and low potassium','Treat volume, chloride, and potassium deficits and remove the cause','Report persistent vomiting, weakness, cramps, or palpitations','Ventricular dysrhythmia with severe hypokalemia','Reduction of Risk Potential'),
('prone-ventilation','prone positioning for severe ARDS','refractory hypoxemia persists despite lung-protective ventilation','Use a trained team to secure airway and lines, protect pressure points and eyes, and monitor response','Families should not reposition the client or touch airway equipment','Tube displacement or sudden hemodynamic collapse occurs during turning','Reduction of Risk Potential'),
('reexpansion-edema','re-expansion pulmonary edema','cough, hypoxemia, and pink sputum follow rapid drainage of a large effusion','Stop or control drainage, support oxygenation, and notify the procedural team','Report severe cough, chest tightness, or breathlessness during or after drainage','Rapid respiratory failure with unilateral edema','Physiological Adaptation'),
('bronchopleural-fistula','bronchopleural fistula','persistent large air leak and failure of lung re-expansion','Maintain drainage-system function, support ventilation, and obtain thoracic evaluation','Report new bubbling, dyspnea, fever, or subcutaneous air','Ventilation fails with tension physiology','Physiological Adaptation'),
('subcutaneous-emphysema','progressive subcutaneous emphysema','crepitus spreads across the chest and neck after thoracic injury','Assess airway and chest-tube patency and notify the provider of progression','Report voice change, neck swelling, breathing difficulty, or rapidly spreading crepitus','Neck expansion compromises the airway','Reduction of Risk Potential'),
('lobectomy-care','post-lobectomy care','a client has chest drainage, pain, and reduced ventilation after lung resection','Support pulmonary hygiene, pain control, mobility, drainage, and complication surveillance','Use incentive breathing and report fever, increasing dyspnea, bleeding, or drainage-system change','Rapid bloody drainage with hypotension','Reduction of Risk Potential'),
('pneumonectomy-care','post-pneumonectomy care','a client has one remaining lung and a closed or specially managed drainage space','Follow surgeon-specific positioning and drainage orders and avoid mediastinal shift from inappropriate manipulation','Protect respiratory reserve and report sudden dyspnea, chest pressure, or palpitations','Acute mediastinal shift with cardiovascular collapse','Reduction of Risk Potential'),
('lung-transplant-rejection','lung transplant rejection','declining spirometry, dyspnea, cough, and low-grade fever','Notify the transplant team and urgently distinguish rejection from infection','Track home spirometry and take immunosuppression exactly as prescribed','Rapid lung-function decline with severe hypoxemia','Physiological Adaptation'),
('lung-transplant-infection','infection after lung transplant','immunosuppression with new fever, sputum, and infiltrate','Obtain prompt transplant-guided infectious evaluation and treatment','Use infection precautions and report fever or respiratory change even when mild','Sepsis with rapidly escalating oxygen need','Physiological Adaptation'),
('chest-physiotherapy','chest physiotherapy','retained secretions require airway-clearance treatment','Schedule around meals, assess tolerance, and combine positioning, percussion, vibration, and cough as prescribed','Perform the taught sequence and stop for severe breathlessness, bleeding, or chest pain','Large hemoptysis or acute hypoxemia occurs during therapy','Basic Care and Comfort'),
('incentive-spirometry','incentive spirometry after surgery','a client takes shallow breaths because of incisional pain','Provide analgesia and coach slow sustained inhalation with regular coughing and mobility','Use the device while awake as instructed rather than rapid repeated blowing','New dyspnea and absent unilateral breath sounds despite exercises','Basic Care and Comfort'),
('pulmonary-rehab','pulmonary rehabilitation','a stable chronic lung client has exertional limitation','Use supervised exercise, breathing retraining, nutrition, medicine optimization, and action planning','Pace activity, use pursed-lip breathing, and report a significant symptom change','Exertion causes syncope, chest pain, or severe desaturation','Health Promotion and Maintenance')
) as c(slug,condition,cue,action,teaching,danger,client_need);

