-- Batch 14: neurologic and sensory catalog.
select public.seed_structured_concept(
  'expansion-batch-14', slug, 'Neurologic and Sensory', condition, cue, action, teaching, danger,
  'Delay neurologic assessment despite an acute change',
  'Encourage unassisted activity during neurologic instability',
  'Stop prescribed therapy without clinician review',
  client_need
)
from (values
('tia','transient ischemic attack','brief focal deficit resolves completely','Treat as an emergency stroke warning and obtain rapid vascular evaluation','Call emergency services for any sudden focal symptom even if it resolves','Recurrent deficit persists or consciousness declines','Physiological Adaptation'),
('hemorrhagic-stroke','intracerebral hemorrhage','headache, vomiting, focal deficit, and severe pressure','Protect airway, control pressure as prescribed, reverse anticoagulation, and obtain neurosurgical care','Report sudden headache, weakness, speech change, or vomiting immediately','Expanding hemorrhage causes herniation signs','Physiological Adaptation'),
('cerebellar-stroke','cerebellar stroke','vertigo, vomiting, ataxia, and occipital headache','Activate stroke care and monitor closely for edema and brainstem compression','Sudden inability to walk with severe vertigo requires emergency evaluation','Declining consciousness with irregular respirations','Physiological Adaptation'),
('carotid-stenosis','symptomatic carotid stenosis','amaurosis fugax or hemispheric TIA with carotid bruit','Start urgent stroke-prevention evaluation and prescribed antiplatelet and vascular care','Report any transient vision, speech, or strength change','A new persistent stroke deficit develops','Reduction of Risk Potential'),
('cerebral-aneurysm','an unruptured cerebral aneurysm','incidental aneurysm with modifiable rupture risks','Control pressure and smoking risk and coordinate surveillance or intervention','Seek emergency care for sudden maximal headache or neurologic change','Sentinel headache progresses to subarachnoid hemorrhage','Reduction of Risk Potential'),
('status-migraine','status migrainosus','debilitating migraine persists for days with vomiting','Exclude secondary emergencies and provide prescribed hydration and migraine rescue therapy','Use an action plan early and avoid medication overuse','New focal deficit, fever, or thunderclap onset occurs','Physiological Adaptation'),
('cluster-headache','cluster headache','severe unilateral orbital pain with tearing and restlessness','Give prescribed high-flow oxygen and rapid abortive therapy','Avoid alcohol during a cluster period and use preventive treatment as prescribed','A first severe headache includes neurologic deficit','Basic Care and Comfort'),
('temporal-arteritis','giant cell arteritis','new temporal headache, jaw claudication, and visual symptoms','Begin urgent corticosteroid treatment and protect vision while confirming diagnosis','Report any vision change immediately','Sudden permanent visual loss develops','Physiological Adaptation'),
('trigeminal-neuralgia','trigeminal neuralgia','brief electric facial pain triggered by touch or chewing','Assess nutrition and triggers and give prescribed neuropathic therapy','Use gentle oral care and softer foods during flares','New facial weakness or persistent sensory loss suggests another cause','Basic Care and Comfort'),
('bells-palsy','Bell palsy','acute unilateral lower and upper facial weakness','Protect the eye and exclude stroke when presentation is atypical','Use lubrication and eye protection until closure returns','Corneal injury develops or limb weakness appears','Reduction of Risk Potential'),
('parkinsons-off','Parkinson disease off episodes','rigidity and freezing recur before medicine doses','Time medicines precisely and use cueing and fall precautions','Do not stop dopaminergic therapy abruptly and plan activity during best mobility','Sudden hyperpyrexia and severe rigidity follow withdrawal','Physiological Adaptation'),
('parkinsons-dysphagia','dysphagia in Parkinson disease','coughing, drooling, and weight loss during meals','Obtain swallowing evaluation and use safe texture, posture, and medication timing','Eat upright and report wet voice, recurrent fever, or choking','Aspiration causes hypoxemia and pneumonia','Reduction of Risk Potential'),
('multiple-sclerosis-relapse','multiple sclerosis relapse','new neurologic deficit lasts over a day without fever','Exclude infection and pseudo-relapse and give prescribed relapse treatment','Manage heat and fatigue and report sustained new symptoms','Rapid weakness compromises breathing or swallowing','Physiological Adaptation'),
('autonomic-dysreflexia','autonomic dysreflexia','spinal injury above T6 with pounding headache and severe hypertension','Sit upright, loosen constriction, find bladder or bowel trigger, and treat pressure','Prevent bladder and bowel triggers and carry an emergency plan','Pressure remains extreme with seizure or stroke signs','Physiological Adaptation'),
('cauda-equina','cauda equina syndrome','saddle anesthesia, urinary retention, and bilateral weakness','Obtain emergency spinal imaging and surgical evaluation','Report new bladder, bowel, saddle sensation, or leg weakness immediately','Progressive paralysis and permanent sphincter loss','Physiological Adaptation'),
('spinal-cord-compression','malignant spinal cord compression','cancer with new back pain, weakness, and bladder change','Immobilize as indicated and obtain emergency imaging and corticosteroid and oncology care','Report new back pain, weakness, numbness, or elimination change','Rapid paraplegia develops','Physiological Adaptation'),
('als-respiratory','amyotrophic lateral sclerosis respiratory decline','weak cough, orthopnea, and falling vital capacity','Assess ventilation, secretion clearance, communication, nutrition, and goals','Discuss noninvasive ventilation and emergency preferences before crisis','Morning confusion progresses to respiratory failure','Physiological Adaptation'),
('huntington-disease','Huntington disease','chorea, cognitive change, impulsivity, and weight loss','Protect safety and nutrition and address psychiatric and family genetic needs','Use high-calorie safe-texture meals and report depression or suicidal thoughts','Severe dysphagia causes aspiration or suicide risk escalates','Psychosocial Integrity'),
('alzheimer-wandering','dementia-related wandering','a cognitively impaired client repeatedly seeks exits','Assess needs and use secure safe walking space, identification, and consistent routine','Use door alerts and identification and notify authorities promptly if missing','The client disappears into extreme weather','Safety and Infection Prevention and Control'),
('delirium-hypoactive','hypoactive delirium','new quiet withdrawal, inattention, and slowed responses','Identify acute cause and protect hydration, mobility, orientation, and safety','Sudden quiet confusion is not normal aging and needs urgent assessment','Reduced responsiveness accompanies sepsis or hypoxemia','Reduction of Risk Potential'),
('normal-pressure-hydrocephalus','normal-pressure hydrocephalus','gait apraxia, cognitive decline, and urinary incontinence','Obtain neurologic imaging and specialist evaluation for potentially reversible disease','Report progressive walking, thinking, and bladder changes','Falls and rapid decline continue without evaluation','Reduction of Risk Potential'),
('hydrocephalus-shunt','ventricular shunt malfunction','headache, vomiting, lethargy, and declining school performance','Assess intracranial pressure and obtain urgent shunt evaluation','Report headache, vomiting, fever, redness, or behavior change','Bradycardia, unequal pupils, and decreasing consciousness occur','Physiological Adaptation'),
('brain-tumor','intracranial tumor','progressive morning headache, seizure, and focal change','Control seizures and pressure and coordinate imaging and oncology or surgery','Report new seizure, worsening headache, vomiting, or deficit','Herniation signs develop','Physiological Adaptation'),
('pituitary-tumor','pituitary macroadenoma','bitemporal field loss and hormonal disturbance','Assess vision and endocrine function and prepare specialist treatment','Report sudden severe headache, vision loss, or collapse','Pituitary apoplexy causes shock and acute blindness','Physiological Adaptation'),
('transsphenoidal-care','care after transsphenoidal surgery','nasal drainage and endocrine shifts are possible','Monitor neurologic status, vision, urine, sodium, and clear drainage without nasal instrumentation','Avoid blowing the nose, bending, and straining','Clear drainage with meningitis signs or severe sodium disturbance occurs','Reduction of Risk Potential'),
('menieres','Ménière disease','episodic vertigo, tinnitus, fullness, and fluctuating hearing','Protect from falls and give prescribed vestibular and fluid-management therapy','Sit or lie down during attacks and limit triggers as directed','Sudden neurologic deficit suggests stroke rather than Ménière disease','Basic Care and Comfort'),
('bppv','benign paroxysmal positional vertigo','brief vertigo triggered by head position without focal deficit','Use prescribed canalith repositioning and protect against falls','Move slowly and seek care for persistent vertigo or neurologic symptoms','Vertigo occurs with weakness, diplopia, or inability to walk','Basic Care and Comfort'),
('labyrinthitis','acute labyrinthitis','prolonged vertigo with hearing symptoms after infection','Assess hydration and neurologic red flags and give prescribed symptom therapy','Avoid driving during vertigo and report focal deficits or worsening hearing','Severe dehydration or central neurologic signs develop','Reduction of Risk Potential'),
('retinal-detachment','retinal detachment','flashes, floaters, and a curtain over vision','Protect the eye and obtain immediate ophthalmologic repair','Seek urgent care for sudden flashes, floaters, or field loss','Central vision rapidly disappears','Physiological Adaptation'),
('acute-angle-glaucoma','acute angle-closure glaucoma','severe eye pain, halos, nausea, and fixed mid-dilated pupil','Give emergency pressure-lowering therapy and obtain ophthalmologic care','Report sudden eye pain, halos, headache, or vomiting immediately','Vision loss progresses with very high pressure','Physiological Adaptation'),
('open-angle-glaucoma','primary open-angle glaucoma','gradual peripheral field loss with elevated pressure','Promote lifelong pressure-lowering therapy and visual-field monitoring','Use drops correctly and do not stop because vision seems unchanged','Rapid worsening occurs because therapy is repeatedly missed','Health Promotion and Maintenance'),
('macular-degeneration','age-related macular degeneration','central distortion and impaired reading with preserved peripheral vision','Arrange retinal evaluation and provide low-vision and risk-reduction support','Use an Amsler grid as directed and report new distortion promptly','Sudden central vision change suggests neovascular bleeding','Health Promotion and Maintenance'),
('diabetic-retinopathy','diabetic retinopathy','diabetes with retinal hemorrhage or neovascular change','Optimize glucose and pressure and obtain timely retinal treatment','Keep dilated eye exams and report sudden floaters or vision loss','Vitreous hemorrhage or retinal detachment causes sudden loss','Reduction of Risk Potential'),
('chemical-eye-burn','chemical eye exposure','pain and vision change after caustic splash','Irrigate immediately and continuously before detailed examination','Begin flushing at once and remove contaminated lenses when possible','Ocular pH remains abnormal with corneal whitening','Safety and Infection Prevention and Control'),
('ocular-trauma','penetrating eye injury','an object is embedded in the globe','Shield both eyes without pressure and obtain emergency ophthalmic surgery','Do not remove or press an embedded object','Fluid leaks from the globe with falling vision','Safety and Infection Prevention and Control'),
('hearing-loss-sudden','sudden sensorineural hearing loss','unilateral hearing drops over hours with tinnitus','Treat as an urgent otologic emergency and arrange prompt corticosteroid evaluation','Report sudden hearing change immediately rather than waiting for wax removal','Hearing loss accompanies stroke signs','Reduction of Risk Potential'),
('otitis-mastoiditis','mastoiditis','ear infection with postauricular swelling, fever, and protruding pinna','Begin urgent IV antimicrobial and surgical evaluation','Complete ear-infection treatment and report swelling behind the ear','Meningitis or intracranial abscess signs develop','Physiological Adaptation'),
('epistaxis-posterior','severe posterior epistaxis','heavy blood drains into the throat with instability','Sit forward, protect airway, apply ordered control, and obtain urgent ENT care','Avoid nose blowing and report persistent heavy bleeding or faintness','Airway compromise or hemorrhagic shock develops','Physiological Adaptation'),
('seizure-first-aid','first aid for generalized seizure','tonic-clonic movement with loss of awareness','Protect from injury, turn to the side, time the event, and support breathing','Do not restrain or place objects in the mouth and call for prolonged seizure','Seizure lasts five minutes or repeats without recovery','Safety and Infection Prevention and Control'),
('absence-seizure','absence seizures','brief staring with eyelid flutter and immediate recovery','Document events and support neurologic evaluation and prescribed therapy','Medication adherence and school observation help track control','Events become prolonged or evolve into convulsive seizure','Reduction of Risk Potential'),
('focal-seizure','focal impaired-awareness seizure','staring, automatisms, and confusion without full responsiveness','Protect safety, observe features and duration, and reorient afterward','Avoid driving until cleared and report increasing frequency or injury','Seizure generalizes with respiratory compromise','Reduction of Risk Potential'),
('antiepileptic-adherence','antiseizure medication adherence','breakthrough seizures follow missed doses','Restore prescribed therapy safely and assess triggers and levels when indicated','Never stop suddenly and use reminders and refill planning','Status epilepticus follows abrupt withdrawal','Health Promotion and Maintenance'),
('meningitis-isolation','initial meningitis precautions','fever, neck stiffness, petechiae, and altered consciousness','Start droplet precautions and urgent culture and antimicrobial care','Close contacts may need prophylaxis and should seek guidance promptly','Purpuric shock and declining consciousness develop','Safety and Infection Prevention and Control'),
('encephalitis','viral encephalitis','fever, behavior change, seizure, and focal neurologic signs','Protect airway, control seizures and pressure, and begin prescribed antiviral care promptly','Report fever with confusion, seizure, or unusual behavior urgently','Refractory seizures and cerebral edema develop','Physiological Adaptation'),
('brain-death-assessment','brain-death evaluation','catastrophic brain injury with absent responsiveness','Ensure prerequisites, exclude confounders, and follow formal neurologic and apnea testing policy','Families need clear consistent explanation that testing follows strict medical and legal standards','Testing proceeds despite hypothermia or sedative confounding','Management of Care'),
('organ-donor-neuro','physiologic support after neurologic death','a potential donor develops hypotension, diabetes insipidus, and hypothermia','Coordinate with donation specialists and support oxygenation, perfusion, temperature, and endocrine balance','Donation decisions remain separate from the independent determination of death','Severe instability threatens organ perfusion','Management of Care'),
